126	template <class CallbacksTuple>
127	struct ProducerLoadCallbacksImpl {
128	  // Callbacks can store non-persistent variables (e.g. tensors) or copies of persistent variables
129	  CallbacksTuple callbacks_tuple;
130	
131	  // Before entry of the subtile load loop
132	  CUTLASS_DEVICE void
133	  begin() {
134	    for_each(callbacks_tuple,
135	      [&] (auto& callbacks) CUTLASS_LAMBDA_FUNC_INLINE {
136	        callbacks.begin();
137	      }
138	    );
139	  }
