141	  // Entry of the subtile load loop. Aux loads usually performed here
142	  // Upon entry the producer acquire of the current subtile lock has completed.
143	  // Upon exit all TMA loads for this subtile must have been issued, with corresponding expect-tx operations
144	  CUTLASS_DEVICE void
145	  step(uint64_t* full_mbarrier_ptr, int epi_m, int epi_n, int load_iteration, bool issue_tma_load) {
146	    for_each(callbacks_tuple,
147	      [&] (auto& callbacks) CUTLASS_LAMBDA_FUNC_INLINE {
148	        callbacks.step(full_mbarrier_ptr, epi_m, epi_n, load_iteration, issue_tma_load);
149	      }
150	    );
