164	  // Exit of the subtile load loop.
165	  CUTLASS_DEVICE void
166	  end() {
167	    for_each(callbacks_tuple,
168	      [] (auto& callbacks) CUTLASS_LAMBDA_FUNC_INLINE {
169	        callbacks.end();
170	      }
171	    );
172	  }
